const pptxgen = require('pptxgenjs');

const pptx = new pptxgen();
pptx.layout = 'LAYOUT_WIDE';
pptx.author = 'OpenAI';
pptx.company = 'OpenAI';
pptx.subject = 'Exec Summary - Bank Datacentre to Azure Migration';
pptx.title = 'Datacentre to Azure Migration Executive Summary';
pptx.lang = 'en-US';
pptx.theme = {
  headFontFace: 'Aptos Display',
  bodyFontFace: 'Aptos',
  lang: 'en-US'
};

const C = {
  navy: '0B1F3A',
  blue: '1565C0',
  azure: '0078D4',
  teal: '00897B',
  green: '2E7D32',
  amber: 'F9A825',
  red: 'C62828',
  gray900: '1F2937',
  gray700: '4B5563',
  gray500: '6B7280',
  gray300: 'D1D5DB',
  gray200: 'E5E7EB',
  gray100: 'F3F4F6',
  white: 'FFFFFF'
};

function addHeader(slide, title, subtitle) {
  slide.addShape(pptx.ShapeType.rect, {
    x: 0, y: 0, w: 13.333, h: 0.65,
    line: { color: C.navy, transparency: 100 },
    fill: { color: C.navy }
  });
  slide.addText(title, {
    x: 0.4, y: 0.14, w: 7.2, h: 0.28,
    fontFace: 'Aptos Display',
    fontSize: 24,
    bold: true,
    color: C.white,
    margin: 0
  });
  if (subtitle) {
    slide.addText(subtitle, {
      x: 8.0, y: 0.17, w: 4.9, h: 0.22,
      align: 'right',
      fontSize: 10,
      color: 'D6E4FF',
      margin: 0
    });
  }
}

function addFooter(slide, text) {
  slide.addLine({
    x: 0.35, y: 7.12, w: 12.6, h: 0,
    line: { color: C.gray300, pt: 1 }
  });
  slide.addText(text, {
    x: 0.4, y: 7.18, w: 6.5, h: 0.18,
    fontSize: 8,
    color: C.gray500,
    margin: 0
  });
}

function addKpiCard(slide, x, y, w, h, accent, title, value, body) {
  slide.addShape(pptx.ShapeType.roundRect, {
    x, y, w, h,
    rectRadius: 0.06,
    line: { color: C.gray200, pt: 1 },
    fill: { color: C.white },
    shadow: { type: 'outer', color: 'D9E2F3', blur: 1, angle: 45, distance: 1, opacity: 0.12 }
  });
  slide.addShape(pptx.ShapeType.rect, {
    x, y, w: 0.12, h,
    line: { color: accent, transparency: 100 },
    fill: { color: accent }
  });
  slide.addText(title, {
    x: x + 0.22, y: y + 0.18, w: w - 0.35, h: 0.22,
    fontSize: 11, bold: true, color: C.gray700, margin: 0
  });
  slide.addText(value, {
    x: x + 0.22, y: y + 0.52, w: w - 0.35, h: 0.38,
    fontSize: 21, bold: true, color: accent, margin: 0
  });
  slide.addText(body, {
    x: x + 0.22, y: y + 1.0, w: w - 0.35, h: h - 1.15,
    fontSize: 9.5, color: C.gray700, valign: 'top', breakLine: false,
    margin: 0.02
  });
}

function addBulletList(slide, x, y, w, items, color = C.gray900, fontSize = 13) {
  const runs = [];
  items.forEach((t) => {
    runs.push({ text: t, options: { bullet: { indent: 12 } } });
  });
  slide.addText(runs, {
    x, y, w, h: 2.2,
    fontSize,
    color,
    breakLine: true,
    paraSpaceAfterPt: 10,
    valign: 'top',
    margin: 0.02
  });
}

function addSectionLabel(slide, x, y, text, fill) {
  slide.addShape(pptx.ShapeType.roundRect, {
    x, y, w: 1.55, h: 0.34,
    rectRadius: 0.05,
    line: { color: fill, transparency: 100 },
    fill: { color: fill }
  });
  slide.addText(text, {
    x: x + 0.08, y: y + 0.07, w: 1.39, h: 0.16,
    fontSize: 9, bold: true, color: C.white, align: 'center', margin: 0
  });
}

// Slide 1
{
  const slide = pptx.addSlide();
  slide.background = { color: 'F8FAFC' };
  addHeader(slide, 'Executive Summary', 'Bank datacentre-to-Azure migration');
  slide.addText('A phased Azure migration can reduce run-rate cost, improve service resilience, and strengthen control effectiveness while supporting regulatory expectations.', {
    x: 0.45, y: 0.92, w: 12.1, h: 0.56,
    fontSize: 18, color: C.gray900, bold: false, margin: 0
  });

  addKpiCard(
    slide, 0.55, 1.75, 3.95, 2.15, C.green,
    'Cost',
    '15–25% lower TCO',
    'Primary levers: datacentre exit, hardware refresh avoidance, elastic scaling, managed services, and FinOps disciplines for sustained savings.'
  );
  addKpiCard(
    slide, 4.68, 1.75, 3.95, 2.15, C.azure,
    'Resilience',
    'Higher availability',
    'Leverage Azure regions, availability zones, automated backup, and infrastructure-as-code to reduce recovery times and improve operational consistency.'
  );
  addKpiCard(
    slide, 8.81, 1.75, 3.95, 2.15, C.red,
    'Security',
    'Stronger control posture',
    'Adopt zero trust, centralized identity, encryption by default, continuous monitoring, and policy enforcement aligned to banking risk and compliance needs.'
  );

  slide.addShape(pptx.ShapeType.roundRect, {
    x: 0.55, y: 4.28, w: 12.2, h: 2.25,
    rectRadius: 0.05,
    line: { color: C.gray200, pt: 1 },
    fill: { color: C.white }
  });
  addSectionLabel(slide, 0.78, 4.48, 'Why now', C.navy);
  addBulletList(slide, 0.82, 4.95, 5.7, [
    'Legacy estate nearing refresh cycle increases capex pressure and operational risk.',
    'Demand for faster product delivery and analytics is constrained by on-prem infrastructure.',
    'Regulators increasingly expect demonstrable resilience, recovery testing, and strong cyber hygiene.'
  ]);

  addSectionLabel(slide, 6.75, 4.48, 'Recommended path', C.teal);
  addBulletList(slide, 6.79, 4.95, 5.55, [
    'Migrate in waves: non-production, customer channels, core adjacencies, then remaining tiered workloads.',
    'Use landing zones, guardrails, and policy-as-code before large-scale workload onboarding.',
    'Track benefits through business cases, service-level metrics, and FinOps governance from day one.'
  ]);

  addFooter(slide, 'Confidential | Executive summary');
}

// Slide 2
{
  const slide = pptx.addSlide();
  slide.background = { color: 'F8FAFC' };
  addHeader(slide, 'Cost', 'Value creation and financial discipline');

  slide.addText('Azure shifts spend from periodic infrastructure refreshes to transparent, optimizable consumption aligned to business demand.', {
    x: 0.45, y: 0.92, w: 12.0, h: 0.4,
    fontSize: 18, color: C.gray900, margin: 0
  });

  slide.addShape(pptx.ShapeType.roundRect, {
    x: 0.55, y: 1.55, w: 6.1, h: 4.95,
    rectRadius: 0.05,
    line: { color: C.gray200, pt: 1 },
    fill: { color: C.white }
  });
  addSectionLabel(slide, 0.8, 1.78, 'Savings drivers', C.green);
  addBulletList(slide, 0.82, 2.2, 5.45, [
    'Eliminate datacentre facilities, power, cooling, and third-party hosting overheads.',
    'Avoid server, storage, and network refresh capex through cloud-native capacity consumption.',
    'Use reserved capacity, savings plans, autoscaling, and storage tiering to reduce steady-state run costs.',
    'Retire technical debt by replacing bespoke tooling with managed platform services where appropriate.'
  ], C.gray900, 12);

  slide.addShape(pptx.ShapeType.roundRect, {
    x: 6.9, y: 1.55, w: 5.85, h: 2.2,
    rectRadius: 0.05,
    line: { color: C.gray200, pt: 1 },
    fill: { color: C.white }
  });
  addSectionLabel(slide, 7.14, 1.78, 'Illustrative economics', C.azure);
  slide.addText([
    { text: 'Years 1–2: ', options: { bold: true, color: C.gray900 } },
    { text: 'migration investment and dual-running may temporarily increase spend.' },
    { text: '\nYears 3+: ', options: { bold: true, color: C.gray900 } },
    { text: 'datacentre exit and optimization typically deliver a net TCO benefit of ' },
    { text: '15–25%', options: { bold: true, color: C.green } },
    { text: ' for suitable application portfolios.' }
  ], {
    x: 7.18, y: 2.2, w: 5.25, h: 1.1,
    fontSize: 11.5, color: C.gray700, margin: 0.02
  });

  slide.addShape(pptx.ShapeType.roundRect, {
    x: 6.9, y: 3.98, w: 5.85, h: 2.52,
    rectRadius: 0.05,
    line: { color: C.gray200, pt: 1 },
    fill: { color: C.white }
  });
  addSectionLabel(slide, 7.14, 4.2, 'Management actions', C.navy);
  addBulletList(slide, 7.18, 4.62, 5.1, [
    'Stand up FinOps with chargeback/showback, tagging standards, and monthly optimization reviews.',
    'Set workload guardrails for SKU choice, environment scheduling, and non-production shutdown.',
    'Measure benefits against baseline cost towers and application business cases.'
  ], C.gray900, 11.5);

  slide.addText('Board implication: approve migration only with benefits tracking, exit milestones, and clear accountability for cloud consumption governance.', {
    x: 0.6, y: 6.72, w: 12.0, h: 0.28,
    fontSize: 10.5, italic: true, color: C.gray700, margin: 0
  });

  addFooter(slide, 'Confidential | Cost');
}

// Slide 3
{
  const slide = pptx.addSlide();
  slide.background = { color: 'F8FAFC' };
  addHeader(slide, 'Resilience and Security', 'Operational continuity and control strength');

  slide.addShape(pptx.ShapeType.roundRect, {
    x: 0.55, y: 1.02, w: 5.9, h: 5.85,
    rectRadius: 0.05,
    line: { color: C.gray200, pt: 1 },
    fill: { color: C.white }
  });
  addSectionLabel(slide, 0.8, 1.25, 'Resilience', C.azure);
  slide.addText('Expected outcomes', {
    x: 0.82, y: 1.72, w: 2.0, h: 0.18, fontSize: 10, bold: true, color: C.gray700, margin: 0
  });
  addBulletList(slide, 0.82, 1.98, 5.2, [
    'Improve service availability using regional redundancy and availability zones.',
    'Reduce recovery times with automated backup, replication, and tested recovery runbooks.',
    'Increase deployment reliability through standard patterns and infrastructure-as-code.'
  ], C.gray900, 11.5);

  slide.addText('Leadership focus', {
    x: 0.82, y: 4.28, w: 2.0, h: 0.18, fontSize: 10, bold: true, color: C.gray700, margin: 0
  });
  addBulletList(slide, 0.82, 4.52, 5.2, [
    'Define tiering by criticality and map each workload to target RTO/RPO.',
    'Validate third-party dependencies, network design, and operational support model.',
    'Evidence regular failover and disaster recovery testing for material services.'
  ], C.gray900, 11.5);

  slide.addShape(pptx.ShapeType.roundRect, {
    x: 6.85, y: 1.02, w: 5.9, h: 5.85,
    rectRadius: 0.05,
    line: { color: C.gray200, pt: 1 },
    fill: { color: C.white }
  });
  addSectionLabel(slide, 7.1, 1.25, 'Security', C.red);
  slide.addText('Expected outcomes', {
    x: 7.12, y: 1.72, w: 2.0, h: 0.18, fontSize: 10, bold: true, color: C.gray700, margin: 0
  });
  addBulletList(slide, 7.12, 1.98, 5.15, [
    'Centralize identity and privileged access with stronger authentication and conditional access.',
    'Apply encryption, key management, logging, and policy enforcement consistently across the estate.',
    'Enhance threat detection and response via cloud-native telemetry and security analytics.'
  ], C.gray900, 11.5);

  slide.addText('Leadership focus', {
    x: 7.12, y: 4.28, w: 2.0, h: 0.18, fontSize: 10, bold: true, color: C.gray700, margin: 0
  });
  addBulletList(slide, 7.12, 4.52, 5.15, [
    'Embed zero-trust principles in landing zones before onboarding sensitive workloads.',
    'Align control design to banking policy, data classification, and regulatory obligations.',
    'Maintain clear shared-responsibility ownership across engineering, security, and operations.'
  ], C.gray900, 11.5);

  addFooter(slide, 'Confidential | Resilience and Security');
}

pptx.writeFile({ fileName: 'Exec_Summary_Bank_Datacentre_to_Azure_Migration.pptx' });
